  if      (u_blendMode == 1)  blended = blendMultiply(fg.rgb, bg.rgb);
  else if (u_blendMode == 2)  blended = blendScreen(fg.rgb, bg.rgb);
  else if (u_blendMode == 3)  blended = blendOverlay(fg.rgb, bg.rgb);
  else if (u_blendMode == 4)  blended = blendColorDodge(fg.rgb, bg.rgb);
  else if (u_blendMode == 5)  blended = blendColorBurn(fg.rgb, bg.rgb);
  else if (u_blendMode == 6)  blended = blendSoftLight(fg.rgb, bg.rgb);
  else if (u_blendMode == 7)  blended = blendHardLight(fg.rgb, bg.rgb);
  else if (u_blendMode == 8)  blended = blendDarken(fg.rgb, bg.rgb);
